#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    string n;    cin >> n;    ll count_0=0, count_1=0;    for (const char c : n) {        if (c == '0') count_0++;        else count_1++;    }    ll length=0;        for(int i=0; i<n.size();i++){        if( n[i] == '0' ){            if(count_1==0){                break;            }            else{                count_1--;                length++;            }         }        else if ( n[i] == '1' ){            if(count_0==0){                break;            }            else{                count_0--;                length++;            }                    }            }    cout<<n.size()-length<<"\n";     }int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}